def solve(arg1: dict) -> str:
    environment = arg1.get('environment')
    log_level = arg1.get('logLevel')
    message = arg1.get('message')

    if environment == 'development':
        if log_level == 'info':
            return f'Console log: {message}'
        elif log_level == 'error':
            return f'Console log: {message}'
    elif environment == 'production':
        if log_level == 'info':
            return f'Console log: {message}'
        elif log_level == 'error':
            return f'Console log: {message}'

    return None
